/**
 * Message formatting utilities for beautiful console output.
 */

const colors = require('../colors/colors');

/**
 * Create a styled badge for log levels.
 * @param {string} text - Badge text.
 * @param {string} color - Color name.
 * @returns {string} Formatted badge.
 */
const createBadge = (text, color) => {
    const bg = 'bg' + color.charAt(0).toUpperCase() + color.slice(1);
    const bgColor = colors[bg] || colors.bgBlue;
    const textColor = colors.white + colors.bold;
    return bgColor + textColor + ` ${text} ` + colors.reset;
};

/**
 * Create a boxed message for bigLog.
 * @param {string} message - Message to box.
 * @param {string} color - Box color.
 * @param {string} emoji - Optional emoji.
 * @returns {string} Boxed message.
 */
const createBox = (message, color, emoji = '') => {
    const lines = message.split('\n');
    const maxLength = Math.max(...lines.map(line => stripAnsi(line).length));
    
    // Box drawing characters
    const topLeft = '╔';
    const topRight = '╗';
    const bottomLeft = '╚';
    const bottomRight = '╝';
    const horizontal = '═';
    const vertical = '║';
    
    const colorCode = colors[color] || colors.blue;
    const horizontalLine = horizontal.repeat(maxLength + 4);
    
    let box = colorCode + topLeft + horizontalLine + topRight + colors.reset + '\n';
    
    // Add emoji line if provided
    if (emoji) {
        const emojiPadding = ' '.repeat(maxLength + 2 - emoji.length);
        box += colorCode + vertical + colors.reset + ` ${emoji}${emojiPadding} ` + colorCode + vertical + colors.reset + '\n';
        box += colorCode + vertical + horizontal.repeat(maxLength + 4) + vertical + colors.reset + '\n';
    }
    
    // Add message lines
    lines.forEach(line => {
        const stripped = stripAnsi(line);
        const padding = ' '.repeat(maxLength - stripped.length);
        box += colorCode + vertical + colors.reset + `  ${line}${padding}  ` + colorCode + vertical + colors.reset + '\n';
    });
    
    box += colorCode + bottomLeft + horizontalLine + bottomRight + colors.reset;
    
    return box;
};

/**
 * Create a simple banner.
 * @param {string} text - Banner text.
 * @param {string} char - Character to use for banner (default '=').
 * @returns {string} Banner string.
 */
const createBanner = (text, char = '=') => {
    const length = stripAnsi(text).length;
    const line = char.repeat(length + 4);
    return `${line}\n  ${text}  \n${line}`;
};

/**
 * Strip ANSI color codes from text.
 * @param {string} text - Text with ANSI codes.
 * @returns {string} Plain text.
 */
const stripAnsi = (text) => {
    return text.replace(/\x1b\[[0-9;]*m/g, '');
};

/**
 * Truncate text with ellipsis.
 * @param {string} text - Text to truncate.
 * @param {number} maxLength - Maximum length.
 * @returns {string} Truncated text.
 */
const truncate = (text, maxLength) => {
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength - 3) + '...';
};

/**
 * Center text within a given width.
 * @param {string} text - Text to center.
 * @param {number} width - Total width.
 * @returns {string} Centered text.
 */
const center = (text, width) => {
    const stripped = stripAnsi(text);
    const padding = Math.max(0, width - stripped.length);
    const leftPad = Math.floor(padding / 2);
    const rightPad = padding - leftPad;
    return ' '.repeat(leftPad) + text + ' '.repeat(rightPad);
};

/**
 * Pad text to the right.
 * @param {string} text - Text to pad.
 * @param {number} width - Total width.
 * @returns {string} Padded text.
 */
const padRight = (text, width) => {
    const stripped = stripAnsi(text);
    const padding = Math.max(0, width - stripped.length);
    return text + ' '.repeat(padding);
};

/**
 * Pad text to the left.
 * @param {string} text - Text to pad.
 * @param {number} width - Total width.
 * @returns {string} Padded text.
 */
const padLeft = (text, width) => {
    const stripped = stripAnsi(text);
    const padding = Math.max(0, width - stripped.length);
    return ' '.repeat(padding) + text;
};

/**
 * Create a progress bar.
 * @param {number} current - Current value.
 * @param {number} total - Total value.
 * @param {number} width - Bar width (default 20).
 * @returns {string} Progress bar string.
 */
const createProgressBar = (current, total, width = 20) => {
    const percentage = Math.min(100, Math.max(0, (current / total) * 100));
    const filled = Math.round((percentage / 100) * width);
    const empty = width - filled;
    
    const bar = colors.green + '█'.repeat(filled) + colors.dim + '░'.repeat(empty) + colors.reset;
    const percent = `${percentage.toFixed(1)}%`;
    
    return `${bar} ${percent}`;
};

/**
 * Create a separator line.
 * @param {number} length - Line length (default 50).
 * @param {string} char - Character to use (default '-').
 * @param {string} color - Color name.
 * @returns {string} Separator line.
 */
const createSeparator = (length = 50, char = '-', color = 'dim') => {
    const colorCode = colors[color] || colors.dim;
    return colorCode + char.repeat(length) + colors.reset;
};

/**
 * Format a key-value pair.
 * @param {string} key - Key name.
 * @param {*} value - Value.
 * @param {number} keyWidth - Width for key column.
 * @returns {string} Formatted key-value string.
 */
const formatKeyValue = (key, value, keyWidth = 20) => {
    const paddedKey = padRight(colors.cyan + key + colors.reset, keyWidth + 9); // +9 for ANSI codes
    return `${paddedKey}: ${colors.white}${value}${colors.reset}`;
};

/**
 * Create a list with bullets.
 * @param {string[]} items - List items.
 * @param {string} bullet - Bullet character (default '•').
 * @returns {string} Formatted list.
 */
const createList = (items, bullet = '•') => {
    return items.map(item => `  ${colors.dim}${bullet}${colors.reset} ${item}`).join('\n');
};

/**
 * Highlight text with background color.
 * @param {string} text - Text to highlight.
 * @param {string} bgColor - Background color name.
 * @returns {string} Highlighted text.
 */
const highlight = (text, bgColor = 'bgYellow') => {
    const bg = colors[bgColor] || colors.bgYellow;
    return bg + colors.black + text + colors.reset;
};

module.exports = {
    createBadge,
    createBox,
    createBanner,
    stripAnsi,
    truncate,
    center,
    padRight,
    padLeft,
    createProgressBar,
    createSeparator,
    formatKeyValue,
    createList,
    highlight,
};